import{_ as t,o as i,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"22. Individual Flexibility Arrangements","description":"","frontmatter":{"title":"22. Individual Flexibility Arrangements","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["education-pd","leave","hours","wages","higher-duties"]},"headers":[],"relativePath":"ebas/mspp/employment/22-individual-flexibility-arrangements.md","filePath":"ebas/mspp/employment/22-individual-flexibility-arrangements.md"}'),a={name:"ebas/mspp/employment/22-individual-flexibility-arrangements.md"};function o(s,e,l,m,p,d){return i(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_22-individual-flexibility-arrangements" tabindex="-1">22. Individual Flexibility Arrangements <a class="header-anchor" href="#_22-individual-flexibility-arrangements" aria-label="Permalink to &quot;22. Individual Flexibility Arrangements&quot;">​</a></h1><p><strong>a.</strong> An Employee and an Employer may enter into an individual flexibility arrangement pursuant to this clause in order to meet the genuine needs of the Employee and Employer. An individual flexibility arrangement must be genuinely agreed to by the Employee and Employer.</p><p><strong>b.</strong> An individual flexibility arrangement may vary the effect of one or more of the following terms of this enterprise agreement:</p><p><strong>(i)</strong> professional development leave (<a href="/eba/ebas/mspp/leave/73-professional-development-leave.html">clause 73</a>)</p><p><strong>(ii)</strong> higher duties (<a href="/eba/ebas/mspp/classification-salaries/52-higher-duties.html">clause 52</a>)</p><p><strong>(iii)</strong> ordinary hours of work (<a href="/eba/ebas/mspp/hours-of-work/55-hours-of-work.html">clause 55.1</a>)</p><p><strong>c.</strong> An Employee may nominate a representative including the Union to assist in negotiations for an individual flexibility arrangement.</p><p><strong>d.</strong> The Employer must ensure that any individual flexibility arrangement will result in the Employee being better off overall than the Employee would have been if no individual flexibility arrangement were agreed to.</p><p><strong>e.</strong> The Employer must ensure that an individual flexibility arrangement is in writing and signed by the Employee and Employer. If the Employee is under 18 years the individual flexibility arrangement must be signed by a parent or guardian of the Employee.</p><p><strong>f.</strong> The Employer must give a copy of the individual flexibility arrangement to the Employee within 14 days after it is agreed to.</p><p><strong>g.</strong> The Employer must ensure that any individual flexibility arrangement sets out:</p><p><strong>(i)</strong> the terms of this enterprise agreement that will be varied by the arrangement;</p><p><strong>(ii)</strong> how the arrangement will vary the effect of the terms;</p><p><strong>(iii)</strong> how the Employee will be better off overall in relation to the terms and conditions of their employment as a result of the arrangement; and</p><p><strong>(iv)</strong> the day on which the arrangement commences.</p><p><strong>h.</strong> The Employer must ensure that any individual flexibility arrangement:</p><p><strong>(i)</strong> is about matters that would be permitted matters under section 172 of the Act if the arrangement were an enterprise agreement;</p><p><strong>(ii)</strong> does not include any term that would be an unlawful term under agreement; and</p><p><strong>(iii)</strong> provides for the arrangement to be terminated: <strong>(A)</strong> by either the Employee or Employer giving a specified period of written notice, with the specified period being not more than 28 days; and <strong>(B)</strong> at any time by written agreement between the Employee and Employer.</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p><strong>i.</strong> An individual flexibility arrangement may be expressed to operate for a specified term or while the Employee is performing a specified role (such as acting in a specified higher position). Such an arrangement will terminate on expiry of the specified term or when the Employee ceases to perform the specified role, unless terminated earlier on notice or by agreement.</p><p>Plain language terms: IFA, individual flex agreement.</p>',22)])])}const y=t(a,[["render",o]]);export{h as __pageData,y as default};
